(function() {
    'use strict';  
    document.addEventListener('DOMContentLoaded', function() {
        initializeUsersDatatable();  
        initializeTooltips();        
    });
    function initializeUsersDatatable() {
        const table = document.querySelector('.datatables-users');
        if (!table) return;  
        $(table).DataTable({
            responsive: true,  
            language: {
                search: "Cari:",                                                   
                lengthMenu: "Tampilkan _MENU_ users",                             
                info: "Menampilkan _START_ sampai _END_ dari _TOTAL_ users",      
                infoEmpty: "Tidak ada data",                                       
                infoFiltered: "(difilter dari _MAX_ total users)",                 
                zeroRecords: "User tidak ditemukan",                               
                emptyTable: "Tidak ada user yang tersedia",                        
                paginate: {
                    first: "Pertama",       
                    last: "Terakhir",       
                    next: "Selanjutnya",    
                    previous: "Sebelumnya"  
                }
            },
            order: [[0, 'asc']],
            pageLength: 10,
            columnDefs: [
                {
                    targets: 4,          
                    orderable: false,    
                    searchable: false    
                }
            ]
        });
    }
    function initializeTooltips() {
        const tooltipTriggerList = [].slice.call(document.querySelectorAll('[data-bs-toggle="tooltip"]'));
        tooltipTriggerList.map(function (tooltipTriggerEl) {
            return new bootstrap.Tooltip(tooltipTriggerEl);
        });
    }
})();  